movieData = FileAttachment("unified_movie_list.json").json()

// Create search input
viewof searchText = Inputs.search(movieData, {
  placeholder: "Buscar títulos...",
  columns: ["title"]
})

// Display filtered results in a table
Inputs.table(searchText, {
  columns: ["record_number", "title", "imdbID"],
  header: {
    record_number: "#",
    title: "Título",
    imdbID: "IMDB ID"
  },
  width: {
    record_number: 80,
    title: 600,
    imdbID: 120
  },
  format: {
    imdbID: id =&gt; id ? htl.html`&lt;a href="https://www.imdb.com/title/${id}/" target="_blank"&gt;🎬 Ver&lt;/a&gt;` : ""
  }
})

